{
  "executive_summary": "A real-time courier bidding system built around Redis-backed atomic claim operations, WebSocket fan-out for sub-second bid delivery, and a delayed-queue scheduler for 15-second timeout auto-assignment. The design centers on a single atomic operation (Redis SETNX on a job lock key) to guarantee exactly-one-winner semantics, with all other complexity pushed to the edges. Peak load: 500 concurrent bid windows × 30 couriers = 15,000 active WebSocket connections, well within a small cluster's capacity.",

  "architecture": {
    "components": [
      {
        "name": "Order Ingestion Service",
        "responsibility": "Receives new orders from the marketplace API, validates them, determines the courier zone, and emits a JobCreated domain event. Stateless HTTP service.",
        "boundaries": "Owns order validation and zone resolution. Does NOT own courier eligibility — delegates that to the Eligibility Service."
      },
      {
        "name": "Eligibility Service",
        "responsibility": "Given a zone and job requirements, resolves the set of eligible couriers (online, in-zone, not already on a job, meets vehicle/capacity requirements). Maintains a materialized view of courier availability.",
        "boundaries": "Owns courier-availability projections. Reads courier state but does not mutate it. Consumes CourierOnline/Offline/BusyFree events."
      },
      {
        "name": "Bid Window Orchestrator",
        "responsibility": "The core component. On JobCreated: (1) queries Eligibility Service for courier list, (2) opens a bid window in Redis with a 15s TTL, (3) fans out job offers via WebSocket Gateway, (4) schedules a 15s delayed task for auto-assignment. Processes incoming AcceptBid commands with atomic claim logic.",
        "boundaries": "Owns the bid window lifecycle and the atomic claim operation. This is the single writer for job assignment decisions. All bid state lives in Redis; the orchestrator is stateless and horizontally scalable."
      },
      {
        "name": "WebSocket Gateway",
        "responsibility": "Maintains persistent WebSocket connections with courier mobile apps. Handles connection lifecycle, heartbeats, authentication. Receives fan-out commands from Bid Window Orchestrator and pushes job offers to specific courier connections. Routes courier accept/reject messages back to the orchestrator.",
        "boundaries": "Owns transport only — zero business logic. Routes messages between couriers and the orchestrator. Uses Redis Pub/Sub for cross-instance fan-out when a courier is connected to a different gateway node."
      },
      {
        "name": "Timeout Scheduler",
        "responsibility": "Manages the 15-second deadline for each bid window. Implemented as a Redis sorted set (score = expiry timestamp) with a polling worker, or as delayed messages on a message queue. On timeout, if no courier has claimed the job, triggers auto-assignment to the highest-rated eligible courier.",
        "boundaries": "Owns only the timer. The actual auto-assignment command is sent to the Bid Window Orchestrator, which uses the same atomic claim path — ensuring no race between a last-second accept and the timeout."
      },
      {
        "name": "Assignment Service",
        "responsibility": "Once a job is claimed (either by courier accept or auto-assignment), publishes JobAssigned event, notifies the winning courier with confirmation, notifies losing couriers that the window is closed, and updates the order state.",
        "boundaries": "Downstream of the claim decision. Owns notification fan-out and order state transition to 'assigned'."
      },
      {
        "name": "Courier State Store",
        "responsibility": "Source of truth for courier profiles, ratings, current status (online/offline/busy), and location. Fed by courier app heartbeats and GPS pings.",
        "boundaries": "Owns courier master data. Exposes read APIs to Eligibility Service. Written to by courier app events."
      }
    ],
    "interfaces": [
      {
        "from": "Order Ingestion Service",
        "to": "Bid Window Orchestrator",
        "contract": "Domain event: JobCreated { jobId, zone, pickupLocation, dropoffLocation, requirements, createdAt }",
        "coupling_type": "event (async, loose)"
      },
      {
        "from": "Bid Window Orchestrator",
        "to": "Eligibility Service",
        "contract": "Sync query: GET /eligible-couriers?zone={z}&requirements={r} → CourierId[], each with rating score",
        "coupling_type": "request-response (sync, moderate)"
      },
      {
        "from": "Bid Window Orchestrator",
        "to": "WebSocket Gateway",
        "contract": "Internal command via Redis Pub/Sub: FanOutJobOffer { jobId, courierIds[], offerPayload } and CloseWindow { jobId, winnerCourierId }",
        "coupling_type": "pub/sub (async, loose)"
      },
      {
        "from": "WebSocket Gateway",
        "to": "Bid Window Orchestrator",
        "contract": "HTTP POST /bids/{jobId}/accept { courierId, timestamp } — synchronous because courier needs immediate win/lose response",
        "coupling_type": "request-response (sync, tight by necessity)"
      },
      {
        "from": "Bid Window Orchestrator",
        "to": "Timeout Scheduler",
        "contract": "Enqueue: ScheduleTimeout { jobId, expiresAt, fallbackCourierId (highest-rated) }",
        "coupling_type": "queue (async, loose)"
      },
      {
        "from": "Bid Window Orchestrator",
        "to": "Assignment Service",
        "contract": "Domain event: JobClaimed { jobId, courierId, claimType: 'accepted' | 'auto-assigned', claimedAt }",
        "coupling_type": "event (async, loose)"
      },
      {
        "from": "Courier Mobile App",
        "to": "WebSocket Gateway",
        "contract": "WebSocket protocol: JSON frames — ServerToClient: { type: 'job_offer' | 'window_closed' | 'you_won', payload } / ClientToServer: { type: 'accept' | 'reject', jobId }",
        "coupling_type": "websocket (persistent, transport-level)"
      }
    ],
    "data_flow": "1. Order placed → Order Ingestion validates → emits JobCreated event. 2. Bid Window Orchestrator consumes event → queries Eligibility Service for eligible couriers (with ratings) → writes bid window to Redis (key: bid:{jobId}, value: {status: 'open', couriers: [...], highestRatedCourierId}) with 20s TTL → publishes FanOutJobOffer to WebSocket Gateway → enqueues 15s timeout. 3. WebSocket Gateway pushes job offer to all eligible courier apps simultaneously. 4. Courier taps 'Accept' → WebSocket Gateway forwards to Orchestrator → Orchestrator executes Redis Lua script: IF bid:{jobId}.status == 'open' THEN SET status='claimed', SET winner=courierId, RETURN 'won' ELSE RETURN 'lost'. 5a. If won: Orchestrator cancels timeout, emits JobClaimed, Gateway sends 'you_won' to winner and 'window_closed' to all others. 5b. If 15s expires with no accept: Timeout fires → Orchestrator runs same atomic claim with highestRatedCourierId as auto-assignment → emits JobClaimed with claimType='auto-assigned'. 6. Assignment Service processes JobClaimed → updates order to 'assigned' → triggers downstream dispatch.",
    "patterns_used": [
      {
        "pattern": "Atomic Compare-and-Swap via Redis Lua Script",
        "rationale": "The core invariant — exactly one courier wins — requires an atomic read-check-write. Redis Lua scripts execute atomically on a single thread, giving us serializable isolation without distributed locks. This is the most battle-tested pattern for first-write-wins in real-time systems. No need for distributed consensus (overkill) or database row locks (too slow for real-time bidding)."
      },
      {
        "pattern": "Fan-Out via Pub/Sub + WebSocket",
        "rationale": "30 couriers per job × 500 concurrent windows = 15,000 messages within seconds. Redis Pub/Sub for internal gateway fan-out plus WebSocket for last-mile delivery gives sub-100ms latency from bid open to courier notification. Polling would add unacceptable latency in a 15-second window."
      },
      {
        "pattern": "Delayed Queue for Timeout (Redis Sorted Set or SQS Delay)",
        "rationale": "Each bid window needs a reliable 15-second timer. A sorted set scored by expiry timestamp with a polling worker (100ms interval) gives ±100ms accuracy — sufficient for this use case. More reliable than in-process timers which die with the process."
      },
      {
        "pattern": "Optimistic Concurrency with Immediate Response",
        "rationale": "The accept flow is synchronous (courier needs to know immediately if they won). The Lua script returns won/lost in <1ms, allowing the gateway to respond to the courier within the same WebSocket frame roundtrip. No eventual consistency ambiguity for the courier UX."
      },
      {
        "pattern": "Event-Driven Architecture for Non-Critical Path",
        "rationale": "Everything after the claim decision (notifications, order updates, analytics) is event-driven and async. This keeps the hot path (accept → claim → respond) as fast as possible while allowing downstream services to process at their own pace."
      },
      {
        "pattern": "Materialized View for Eligibility",
        "rationale": "Courier availability is a read-hot projection built from status change events. Avoids querying multiple services at bid-window-open time. The projection is eventually consistent but refreshed frequently (courier heartbeats every 5-10s), which is acceptable — a courier going offline mid-window simply doesn't accept."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Bidding",
        "classification": "core",
        "aggregates": [
          {
            "name": "BidWindow",
            "root_entity": "BidWindow",
            "invariants": [
              "A BidWindow can only be claimed once (status transitions: Open → Claimed | Expired, never backwards)",
              "Only an eligible courier can claim a window",
              "Claim is rejected if window status is not Open"
            ],
            "entities": ["BidWindow"],
            "value_objects": ["BidWindowId", "JobOffer", "ClaimResult", "WindowStatus"],
            "domain_events": ["BidWindowOpened", "JobClaimed", "BidWindowExpired"]
          }
        ]
      },
      {
        "name": "Order Management",
        "classification": "supporting",
        "aggregates": [
          {
            "name": "Order",
            "root_entity": "Order",
            "invariants": [
              "Order transitions: Created → Bidding → Assigned → InProgress → Delivered",
              "An order can only be assigned to one courier"
            ],
            "entities": ["Order"],
            "value_objects": ["OrderId", "PickupLocation", "DropoffLocation", "OrderStatus"],
            "domain_events": ["OrderCreated", "OrderAssigned"]
          }
        ]
      },
      {
        "name": "Courier Management",
        "classification": "supporting",
        "aggregates": [
          {
            "name": "Courier",
            "root_entity": "Courier",
            "invariants": [
              "A courier can only be assigned one active job at a time",
              "Courier rating is derived from completed deliveries"
            ],
            "entities": ["Courier"],
            "value_objects": ["CourierId", "CourierRating", "CourierStatus", "Zone", "VehicleType"],
            "domain_events": ["CourierWentOnline", "CourierWentOffline", "CourierBecameBusy", "CourierBecameFree"]
          }
        ]
      },
      {
        "name": "Notification",
        "classification": "generic",
        "aggregates": []
      }
    ],
    "context_map": [
      {
        "upstream": "Order Management",
        "downstream": "Bidding",
        "relationship": "Customer-Supplier — Order Management publishes OrderCreated; Bidding consumes it to open bid windows. Bidding can request changes to the event schema but Order Management owns the model."
      },
      {
        "upstream": "Courier Management",
        "downstream": "Bidding",
        "relationship": "Conformist — Bidding consumes courier availability and rating data as-is. The Eligibility Service acts as a lightweight ACL, projecting Courier Management events into a bidding-optimized read model."
      },
      {
        "upstream": "Bidding",
        "downstream": "Order Management",
        "relationship": "Customer-Supplier — Bidding publishes JobClaimed; Order Management consumes it to transition order state to Assigned."
      },
      {
        "upstream": "Bidding",
        "downstream": "Notification",
        "relationship": "Open Host Service — Bidding publishes domain events; Notification subscribes and handles all push/SMS/email delivery. Generic subdomain, replaceable."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Redis Lua script for atomic claims instead of database-level locking",
      "gains": "Sub-millisecond claim latency. Single-threaded atomicity without distributed lock coordination. Proven pattern at scale (used by ticket systems, flash sales). Horizontally scalable via Redis Cluster with job-key-based sharding.",
      "sacrifices": "Redis is in-memory — claim state must be persisted to a durable store asynchronously. If Redis crashes mid-claim, a small window of data loss exists. Requires Redis operational expertise.",
      "alternatives_considered": [
        "PostgreSQL SELECT FOR UPDATE — durable but 5-10x slower, connection pool pressure at 500 concurrent windows",
        "Distributed lock (Redlock) — unnecessary complexity since a single Redis instance handles the load, and the Lua script is already atomic",
        "Optimistic locking with version column — requires retry loops, poor UX for real-time bidding"
      ]
    },
    {
      "decision": "WebSocket for courier communication instead of SSE or polling",
      "gains": "Bidirectional: couriers can accept directly over the same connection. Sub-100ms delivery. Connection multiplexing for future features (live tracking, chat).",
      "sacrifices": "Stateful connections complicate scaling and deployment (sticky sessions or Redis-based session routing needed). More complex than SSE for server-to-client-only scenarios.",
      "alternatives_considered": [
        "Server-Sent Events + HTTP POST for accept — simpler server-side but two channels to manage, mobile SDK support is weaker",
        "Long polling — too much latency variance for a 15-second window",
        "Push notifications (FCN/APNS) — unreliable latency (1-30s), not suitable for real-time competitive bidding"
      ]
    },
    {
      "decision": "Synchronous eligibility query at window open time instead of pre-computed assignment",
      "gains": "Freshest possible courier availability data at the moment of bidding. Simple to reason about. No stale pre-computation.",
      "sacrifices": "Adds ~10-50ms latency to window opening. Eligibility Service is on the critical path — if it's down, no windows open.",
      "alternatives_considered": [
        "Pre-computed courier pools per zone refreshed every N seconds — faster but stale, could send offers to offline couriers",
        "Lazy evaluation (send to zone, let couriers self-filter) — simpler but wastes bandwidth and creates poor UX for ineligible couriers"
      ]
    },
    {
      "decision": "Single auto-assign fallback (highest-rated courier) instead of a ranked cascade",
      "gains": "Simplicity. One fallback decision. Predictable for couriers. Avoids complex priority queue logic under time pressure.",
      "sacrifices": "If the highest-rated courier is actually unavailable (app crash, network issue), the job needs manual re-queue. Could be unfair to lower-rated couriers who never get auto-assigned.",
      "alternatives_considered": [
        "Ranked cascade: try #1 rated for 5s, then #2, etc. — complex, extends total wait time, poor customer experience",
        "Round-robin auto-assign — fairer but ignores quality signals",
        "Re-open a second bid window — adds latency, customer is already waiting"
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Bidding Strategy",
      "evolution_path": "Currently first-accept-wins. The atomic claim abstraction can evolve to support scored bidding (collect all bids in 15s, pick best) by changing the Lua script from immediate-claim to collect-and-rank. The BidWindow aggregate's status machine accommodates this with a new 'Evaluating' state."
    },
    {
      "area": "Eligibility Rules",
      "evolution_path": "The Eligibility Service is a standalone query service. Rules can evolve from simple zone+availability to ML-based matching (predicted accept rate, ETA optimization) without touching the bidding core. Swap the implementation behind the same interface."
    },
    {
      "area": "Timeout Duration",
      "evolution_path": "The 15-second window is a configuration parameter on the bid window, not a system constant. Can be made dynamic per zone (shorter in dense areas, longer in sparse areas) or per time-of-day without code changes."
    },
    {
      "area": "Transport Layer",
      "evolution_path": "The WebSocket Gateway is a pure transport adapter. Can be swapped for gRPC streaming, SSE, or MQTT for IoT-class devices without touching business logic. The internal fan-out contract (Redis Pub/Sub commands) remains stable."
    },
    {
      "area": "Auto-Assignment Strategy",
      "evolution_path": "Current: highest-rated. Future: closest courier, best ETA, fairness-weighted rotation. The strategy is a pluggable function passed to the timeout handler — clean extension point."
    }
  ],

  "rigidity_points": [
    {
      "area": "Atomic Claim Path (Redis Lua Script)",
      "reason": "This is the single most critical invariant in the system. It MUST remain a single atomic operation. Any refactoring that splits this into multiple steps (e.g., check-then-set across services) introduces race conditions. This rigidity is intentional and must be defended."
    },
    {
      "area": "BidWindow Status Machine",
      "reason": "Open → Claimed | Expired with no backward transitions. This state machine is the heart of correctness. Adding states is fine (e.g., 'Evaluating'), but allowing backward transitions or branching would break the exactly-once-assignment guarantee."
    },
    {
      "area": "Redis as Bid State Store",
      "reason": "The latency requirements (<5ms claim round-trip) lock us into an in-memory store for the hot path. Moving bid state to a disk-based database would break real-time guarantees. Redis (or equivalent: KeyDB, DragonflyDB) is a hard dependency."
    }
  ],

  "risks": [
    {
      "risk": "Redis single point of failure — if the Redis instance holding bid windows crashes, all active bid windows are lost",
      "severity": "critical",
      "mitigation": "Redis Sentinel for automatic failover with sub-second detection. Async replication to a replica (accept ~1s data loss window). For belt-and-suspenders: after each claim, immediately persist JobClaimed to a durable store (Postgres/Kafka). On Redis recovery, replay unclaimed windows. Consider Redis Cluster for data sharding across 3+ nodes."
    },
    {
      "risk": "WebSocket connection storm — 15,000 concurrent connections across gateway nodes, with reconnection thundering herd after a gateway restart",
      "severity": "high",
      "mitigation": "Distribute connections across 3+ gateway nodes behind a load balancer with least-connections routing. Implement exponential backoff with jitter on client reconnection. Set connection limits per node. Use a connection-lightweight runtime (Node.js, Go, or Rust) for the gateway — each can handle 50K+ concurrent WebSockets."
    },
    {
      "risk": "Timeout race condition — a courier accepts at T=14.9s while the timeout fires at T=15.0s, both attempting to claim",
      "severity": "high",
      "mitigation": "Both paths use the identical atomic Lua script. Only one can succeed. The Lua script's atomic check-and-set guarantees exactly one winner regardless of timing. The timeout worker, upon receiving a 'lost' result, simply no-ops. This is solved by design."
    },
    {
      "risk": "Eligibility Service latency spike delays window opening, degrading customer experience",
      "severity": "medium",
      "mitigation": "Circuit breaker on the eligibility query with a fallback: use a cached zone-level courier list (refreshed every 10s). Accept slightly stale eligibility data over failing to open a window. Set a 200ms timeout on the eligibility call."
    },
    {
      "risk": "Courier app clock skew — courier sees offer but network latency eats into the 15-second window",
      "severity": "medium",
      "mitigation": "The 15-second timer is server-side only. The client displays a countdown but the server is authoritative. Include server timestamp in the offer payload so the client can calculate remaining time accounting for observed latency. Add 500ms grace period server-side (actual timeout at 15.5s) to absorb network jitter."
    },
    {
      "risk": "Hot courier problem — a highly-rated courier in a busy zone receives dozens of simultaneous offers, overwhelming their app",
      "severity": "medium",
      "mitigation": "Cap concurrent offers per courier (e.g., max 3 active windows). The Eligibility Service filters out couriers who already have N pending offers. This also prevents a single courier from accepting one job and leaving others to timeout."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Implement in three phases. Phase 1 (MVP): Single Redis instance, single WebSocket gateway node, Bid Window Orchestrator as a monolith service handling eligibility inline. Validate the atomic claim Lua script and the 15-second timeout under load. Phase 2 (Scale): Extract Eligibility Service, add Redis Sentinel, scale to 3 WebSocket gateway nodes with Redis Pub/Sub for cross-node fan-out. Phase 3 (Resilience): Add durable event log (Kafka), implement circuit breakers, build monitoring dashboards for bid window metrics (claim latency p99, timeout rate, offer-to-accept conversion).",
    "files_to_create_or_modify": [
      "src/bidding/domain/BidWindow.ts — Aggregate root with status machine (Open/Claimed/Expired), claim() method, expire() method",
      "src/bidding/domain/events.ts — BidWindowOpened, JobClaimed, BidWindowExpired domain events",
      "src/bidding/infrastructure/RedisBidWindowRepository.ts — Redis-backed repository, encapsulates Lua scripts",
      "src/bidding/infrastructure/lua/claim-job.lua — Atomic Lua script: IF status==open THEN set claimed+winner RETURN won ELSE RETURN lost",
      "src/bidding/application/BidWindowOrchestrator.ts — Application service: openWindow(), acceptBid(), handleTimeout()",
      "src/bidding/application/TimeoutScheduler.ts — Redis sorted set poller, triggers handleTimeout on expiry",
      "src/gateway/WebSocketGateway.ts — Connection management, auth, message routing, Redis Pub/Sub subscription",
      "src/eligibility/EligibilityService.ts — Query service with materialized courier availability view",
      "src/assignment/AssignmentService.ts — Downstream consumer of JobClaimed events, updates order state",
      "infrastructure/redis/docker-compose.yml — Redis with Sentinel for local development"
    ],
    "patterns_to_follow": "Hexagonal architecture for the Bidding context: domain model at center (no framework dependencies), application services as use-case orchestrators, infrastructure adapters for Redis/WebSocket/HTTP. Domain events as the primary integration mechanism between bounded contexts. Repository pattern for aggregate persistence. All time-sensitive operations use server-authoritative timestamps.",
    "pitfalls_to_avoid": [
      "DO NOT split the claim operation across multiple Redis commands — it MUST be a single Lua script. MULTI/EXEC is NOT sufficient because the conditional logic must be atomic.",
      "DO NOT use in-process timers (setTimeout) for the 15-second window — process restarts lose all timers. Use Redis sorted sets or a persistent delayed queue.",
      "DO NOT let the WebSocket Gateway contain business logic — it is a pure transport adapter. Claim decisions happen in the Orchestrator.",
      "DO NOT query courier availability at accept time — only at window-open time. At accept time, just check if the window is open and the courier is in the eligible set (stored in the bid window itself).",
      "DO NOT use database transactions for the claim — the latency budget is <5ms. Disk-based stores cannot reliably meet this under load.",
      "DO NOT fan out offers via individual HTTP calls to each courier — use pub/sub with a single publish per job. Let the gateway handle per-connection delivery.",
      "DO NOT assume WebSocket connections are reliable — implement heartbeat/ping-pong and handle reconnection gracefully. A courier who disconnects and reconnects within 15s should still see active offers."
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 88,
    "high_confidence_areas": [
      "Atomic claim via Redis Lua script — this is a proven pattern used in ticket booking, flash sales, and ride-hailing systems",
      "WebSocket fan-out architecture — 15K connections is well within commodity hardware capabilities",
      "Event-driven integration between bounded contexts — standard DDD integration pattern",
      "Timeout handling via Redis sorted sets — battle-tested approach for delayed job processing"
    ],
    "low_confidence_areas": [
      "Exact auto-assignment strategy when highest-rated courier is unreachable — may need a retry cascade, which adds complexity to the timeout path",
      "Optimal number of WebSocket gateway nodes and Redis Cluster shards — depends on actual traffic patterns and cloud provider capabilities, needs load testing",
      "Whether 500 concurrent bid windows is the steady-state or burst peak — sizing decisions change significantly between the two"
    ],
    "assumptions": [
      "500 concurrent bid windows is peak load, not average — average is significantly lower",
      "Courier mobile apps maintain persistent WebSocket connections while online",
      "Network latency between courier app and server is <500ms for the vast majority of couriers",
      "Redis can be deployed with Sentinel or Cluster for HA — the operations team has Redis expertise",
      "The 30 couriers per zone are pre-registered and their eligibility attributes are known ahead of time",
      "Courier ratings are pre-computed and do not need real-time recalculation during bid windows"
    ]
  }
}
